/**
 * @fileoverview Text constants.
 * @module module/Text/constants
 */

import { defineParts } from '../shared/definePart.js';

export const CLS = Object.freeze({
    ROOT: 'text',
});

export const DEFAULTS = Object.freeze({});

export const PART = defineParts('Text', {
    ROOT: { class: 'text-root', aliases: ['root', 'text', 'p'] },
});

PART.ROOT.jit = 'text-[var(--tx-size)] fg-[var(--tx-text)] [font-family:var(--tx-font-stack)] [line-height:var(--tx-leading)]';
